// Utility: sigmoid function
inline double sigmoid(double z) {
  return 1.0 / (1.0 + std::exp(-z));
}

// all rcpp functions should only use past information, so they can also be used in live trading


// [[Rcpp::export]]
Rcpp::DataFrame twoline_cross(const Rcpp::NumericVector &fast_line, const Rcpp::NumericVector &slow_line)
{
  const int n = fast_line.size();
  if (slow_line.size() != n) {
    Rcpp::stop("two line vector must have the same length.");
  }

  Rcpp::IntegerVector bars_since_cross(n);
  Rcpp::NumericVector cycle_type(n, NA_REAL);    // 1 = up, -1 = down

  int last_cross       = NA_INTEGER;
  int last_cross_type  = 0;   // 1 = up, -1 = down, 0 = none yet

  for (int i = 0; i < n; ++i) {

    const double fast = fast_line[i];
    const double slow = slow_line[i];

    if (i > 0) {
      const double fast_prev = fast_line[i - 1];
      const double slow_prev = slow_line[i - 1];

      const bool valid_prev =
        !Rcpp::NumericVector::is_na(fast_prev) &&
        !Rcpp::NumericVector::is_na(slow_prev);

      const bool valid_cur =
        !Rcpp::NumericVector::is_na(fast) &&
        !Rcpp::NumericVector::is_na(slow);

      bool crossed_up   = false;
      bool crossed_down = false;

      if (valid_prev && valid_cur) {
        crossed_up   = (fast_prev < slow_prev) && (fast >= slow);
        crossed_down = (fast_prev > slow_prev) && (fast <= slow);
      }

      if (crossed_up || crossed_down) {
        last_cross = i;
        bars_since_cross[i] = 0;
        last_cross_type = crossed_up ? 1 : -1;
      } else if (last_cross != NA_INTEGER) {
        if (valid_cur) {
          bars_since_cross[i] = i - last_cross;
        } else {
          bars_since_cross[i] = NA_INTEGER;
        }
      } else {
        bars_since_cross[i] = NA_INTEGER;
      }

    } else {
      bars_since_cross[i] = NA_INTEGER;
    }

    cycle_type[i] = last_cross_type;
	}

  return Rcpp::DataFrame::create(

    Rcpp::_["cycle_type"] = cycle_type,
    Rcpp::_["bsc"] = bars_since_cross

  );
}